import React, { useState } from 'react';
import './ChatBox.css';
import ImportDataSidebar from './ImportDataSidebar';

const ChatBox = ({ domain, project, issueType }) => {
  const [importedData, setImportedData] = useState(null);

  const handleImportData = async () => {
    if (!domain || !project || !issueType) {
      alert('Please select a valid domain, project, and issue type.');
      return;
    }

    try {
      const response = await fetch('https://localhost:7216/api/ImportData', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ domain, project, issueType }),
      });

      if (response.ok) {
        const data = await response.json();
        setImportedData(data);  // Set the data to be displayed in the sidebar
      } else {
        alert('Failed to import data');
      }
    } catch (error) {
      console.error('Error importing data:', error);
      alert('Error importing data');
    }
  };

  return (
    <div className="chatbox-container">
      <button onClick={handleImportData}>Import Data</button>

      {/* Conditionally render ImportDataSidebar if data is available */}
      {importedData && <ImportDataSidebar data={importedData} />}
    </div>
  );
};

export default ChatBox;
